  onChange: (v: string) => void;
}): JSX.Element {
  return (
    <label className="flex items-center gap-2 rounded-md border border-border bg-background px-2 py-1.5 text-sm">
      <Icons.search size={ICON_SIZE.chrome} className="text-muted" aria-hidden="true" />
