import {
  type CSSProperties,
  type JSX,
  type KeyboardEvent,
  useCallback,
  useRef,
  useState,
} from 'react';
import { Icons, ICON_SIZE } from '@bim-ai/ui';
import {
  alignmentForPick,
  compassLabelFromAzimuth,
  type ViewCubeAlignment,
  type ViewCubeCorner,
  type ViewCubeFace,
  type ViewCubePick,
} from './viewCubeAlignment';

/**
 * ViewCube widget — spec §15.4.
 *
 * 96 × 96 px CSS-3D cube sitting top-right of the 3D canvas. Faces +
 * top corners are clickable (snap camera to that alignment). The cube
 * also supports drag-to-orbit: dragging anywhere on the stage orbits
 * the main camera live via the `onDrag` callback.
 *
 * The cube tracks the camera's full pose (azimuth + elevation) rather
 * than only azimuth, so it mirrors the scene orientation exactly.
 */

export interface ViewCubeProps {
  currentAzimuth: number;
  /** Camera elevation in radians (0 = horizontal, π/2 = straight down). */
  currentElevation: number;
  onPick: (pick: ViewCubePick, alignment: ViewCubeAlignment) => void;
  /** Raw pixel deltas during a drag. Viewport calls rig.orbit(dx, dy). */
  onDrag?: (dxPx: number, dyPx: number) => void;
  onHome?: () => void;
  /** Optional className for positioning. */
  className?: string;
}

const CUBE_SIZE_PX = 68;
const HALF = CUBE_SIZE_PX / 2;
const DRAG_THRESHOLD_PX = 4;

const TOP_CORNERS: { id: ViewCubeCorner; left: string; top: string }[] = [
  { id: 'TOP-NW', left: '6%', top: '6%' },
  { id: 'TOP-NE', left: '94%', top: '6%' },
  { id: 'TOP-SW', left: '6%', top: '94%' },
  { id: 'TOP-SE', left: '94%', top: '94%' },
];

interface FaceDef {
  id: ViewCubeFace;
  label: string;
  transform: string;
  /** Fraction of --color-foreground mixed into --color-surface (0–1). */
  shade: number;
}

const FACES: FaceDef[] = [
  { id: 'FRONT', label: 'FRONT', transform: `rotateY(0deg) translateZ(${HALF}px)`, shade: 0.04 },
  { id: 'BACK', label: 'BACK', transform: `rotateY(180deg) translateZ(${HALF}px)`, shade: 0.12 },
  { id: 'RIGHT', label: 'RIGHT', transform: `rotateY(90deg) translateZ(${HALF}px)`, shade: 0.08 },
  { id: 'LEFT', label: 'LEFT', transform: `rotateY(-90deg) translateZ(${HALF}px)`, shade: 0.08 },
  { id: 'TOP', label: 'TOP', transform: `rotateX(90deg) translateZ(${HALF}px)`, shade: 0.0 },
  {
    id: 'BOTTOM',
    label: 'BTM',
    transform: `rotateX(-90deg) translateZ(${HALF}px)`,
    shade: 0.22,
  },
];

export function ViewCube({
  currentAzimuth,
  currentElevation,
  onPick,
  onDrag,
  onHome,
  className,
}: ViewCubeProps): JSX.Element {
  const dragRef = useRef({ dragging: false, totalMoved: 0 });
  const suppressNextClickRef = useRef(false);
  const [isDragging, setIsDragging] = useState(false);

  function emit(pick: ViewCubePick): void {
    onPick(pick, alignmentForPick(pick));
  }

  function handleKey(event: KeyboardEvent<HTMLDivElement>): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      emit({ kind: 'home' });
      onHome?.();
    }
  }

  const handlePointerDown = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (e.button !== 0) return;
      dragRef.current = { dragging: true, totalMoved: 0 };
      setIsDragging(true);
      document.body.style.cursor = 'grabbing';

      const onMove = (ev: PointerEvent) => {
        const dx = ev.movementX;
        const dy = ev.movementY;
        dragRef.current.totalMoved += Math.abs(dx) + Math.abs(dy);
        onDrag?.(dx, dy);
      };

      const onUp = () => {
        if (dragRef.current.totalMoved > DRAG_THRESHOLD_PX) {
          suppressNextClickRef.current = true;
        }
        dragRef.current.dragging = false;
        setIsDragging(false);
        document.body.style.cursor = '';
        window.removeEventListener('pointermove', onMove);
        window.removeEventListener('pointerup', onUp);
      };

      window.addEventListener('pointermove', onMove);
      window.addEventListener('pointerup', onUp);
    },
    [onDrag],
  );

  const handleClickCapture = useCallback((e: React.MouseEvent) => {
    if (suppressNextClickRef.current) {
      e.stopPropagation();
      suppressNextClickRef.current = false;
    }
  }, []);

  // Cube orientation mirrors camera exactly: azimuth = horizontal rotation,
  // elevation = vertical tilt. The -elevation maps camera look-direction to
  // cube top-down rotation (elevation=0 → see front face, elevation=π/2 → see top face).
  const azimuthDeg = (-currentAzimuth * 180) / Math.PI;
  const elevationDeg = (currentElevation * 180) / Math.PI;

  const stageStyle: CSSProperties = {
    perspective: '320px',
    width: CUBE_SIZE_PX,
    height: CUBE_SIZE_PX,
    position: 'relative',
    cursor: isDragging ? 'grabbing' : 'grab',
  };

  const cubeStyle: CSSProperties = {
    position: 'absolute',
    inset: 0,
    transformStyle: 'preserve-3d',
    transform: `rotateX(${-elevationDeg}deg) rotateY(${azimuthDeg}deg)`,
    transition: isDragging ? 'none' : 'transform var(--motion-slow) var(--ease-snap)',
  };

  return (
    <div
      data-testid="view-cube"
      role="group"
      aria-label="ViewCube"
      onKeyDown={handleKey}
      className={[
        'flex flex-col items-center gap-1.5 rounded-xl border border-border/60 bg-background/80 p-1.5 shadow-elev-2 backdrop-blur-sm',
        className ?? '',
      ].join(' ')}
    >
      {/* Stage: drag here to orbit; click a face/corner to snap. */}
      <div
        data-testid="view-cube-stage"
        style={stageStyle}
        onPointerDown={handlePointerDown}
        onClickCapture={handleClickCapture}
      >
        <div style={cubeStyle} data-cube-stage="true">
          {FACES.map((face) => (
            <CubeFace
              key={face.id}
              face={face}
              onClick={() => emit({ kind: 'face', face: face.id })}
            />
          ))}
        </div>

        {TOP_CORNERS.map((c) => (
          <button
            key={c.id}
            type="button"
            onClick={() => emit({ kind: 'corner', corner: c.id })}
            aria-label={`Align camera to ${c.id}`}
            data-corner={c.id}
            style={{
              position: 'absolute',
              left: c.left,
              top: c.top,
              transform: 'translate(-50%, -50%)',
              width: 12,
              height: 12,
              borderRadius: 6,
              border: '1px solid var(--color-border)',
              background: 'var(--color-surface)',
              cursor: 'pointer',
              opacity: 0.8,
              padding: 0,
            }}
            className="hover:bg-surface-strong"
          />
        ))}
      </div>

      <div className="flex w-full items-center justify-between gap-1">
        <Compass currentAzimuth={currentAzimuth} />
        <button
          type="button"
          onClick={() => {
            emit({ kind: 'home' });
            onHome?.();
          }}
          aria-label="Reset to default view"
          title="Drag cube to orbit · click face to align · click ↺ to reset"
          className="inline-flex h-5 w-5 items-center justify-center rounded text-muted hover:bg-surface hover:text-foreground"
        >
          <Icons.viewCubeReset size={12} aria-hidden="true" />
        </button>
      </div>
    </div>
  );
}

function CubeFace({ face, onClick }: { face: FaceDef; onClick: () => void }): JSX.Element {
  const bgColor =
    face.shade === 0
      ? 'var(--color-surface)'
      : `color-mix(in srgb, var(--color-surface) ${Math.round((1 - face.shade) * 100)}%, var(--color-foreground) ${Math.round(face.shade * 100)}%)`;

  const style: CSSProperties = {
    position: 'absolute',
    inset: 0,
    transform: face.transform,
    background: bgColor,
    border: '1px solid var(--color-border)',
    color: 'var(--color-foreground)',
    fontSize: 7,
    fontWeight: 600,
    letterSpacing: '0.1em',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    cursor: 'grab',
    backfaceVisibility: 'hidden',
    boxShadow: 'inset 0 0 0 1px color-mix(in srgb, var(--color-border) 40%, transparent)',
    userSelect: 'none',
    opacity: 0.9,
  };

  return (
    <button
      type="button"
      onClick={onClick}
      aria-label={`Align camera to ${face.id}`}
      data-face={face.id}
      style={style}
      className="hover:brightness-110"
    >
      {face.label}
    </button>
  );
}

function Compass({ currentAzimuth }: { currentAzimuth: number }): JSX.Element {
  const label = compassLabelFromAzimuth(currentAzimuth);
  return (
    <div
      role="img"
      aria-label={`Compass · north toward ${label}`}
      data-testid="view-cube-compass"
      data-cardinal={label}
      className="flex items-center gap-0.5 text-[10px] font-medium text-muted"
    >
      <span aria-hidden="true" className="opacity-50">⌖</span>
      <span>{label}</span>
    </div>
  );
}

import {
  type CSSProperties,
  type JSX,
  type KeyboardEvent,
  type ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { Icons, IconLabels, ICON_SIZE, type LucideLikeIcon } from '@bim-ai/ui';

/**
 * LeftRail / Project Browser — spec §12.
 *
 * - Sticky header with a search field that filters every row by label / id.
 * - Vertically stacked sections (PROJECT / VIEWS / SHEETS / SCHEDULES /
 *   FAMILIES / EVIDENCE) with uppercase eyebrow labels.
 * - `role="tree"` semantics; each row is a `treeitem` with `aria-expanded`
 *   when it has children. Disclosure triangle is a lucide chevron.
 * - Keyboard: `ArrowDown`/`ArrowUp` move focus row-to-row; `ArrowRight`
 *   expands a closed parent or moves into its first child; `ArrowLeft`
 *   collapses an open parent or moves to its parent. `Enter` activates
 *   the focused row. `F2` invokes `onRename(rowId)`.
 *
 * Caller owns activeRowId, expansion state by default (uncontrolled), and
 * drag-drop reorder. The collapsed (icon-strip) variant is exposed as
 * `<LeftRailCollapsed/>` so AppShell can swap on `[`.
 */

export type LeftRailSection = {
  id: string;
  label: string;
  icon?: LucideLikeIcon;
  rows: LeftRailRow[];
};

export type LeftRailRow = {
  id: string;
  label: string;
  /** Lucide icon component to render at 12 px. Optional. */
  icon?: LucideLikeIcon;
  /** Subrows if any — drives the disclosure triangle and `aria-expanded`. */
  children?: LeftRailRow[];
  /** Optional secondary line shown after the label (muted). */
  hint?: string;
};

export interface LeftRailProps {
  sections: LeftRailSection[];
  activeRowId?: string;
  onRowActivate?: (id: string) => void;
  onRowRename?: (id: string) => void;
  /** Initial expanded set; uncontrolled. */
  defaultExpanded?: ReadonlySet<string>;
  /** Optional hook for context-menu invocation (right-click). */
  onRowContextMenu?: (id: string, event: { x: number; y: number }) => void;
}

/** Flatten sections + rows into a focusable order list. */
function flatten(
  sections: LeftRailSection[],
  expanded: ReadonlySet<string>,
): { id: string; depth: number; row: LeftRailRow; sectionId: string }[] {
  const out: { id: string; depth: number; row: LeftRailRow; sectionId: string }[] = [];
  function visit(rows: LeftRailRow[], depth: number, sectionId: string): void {
    for (const r of rows) {
      out.push({ id: r.id, depth, row: r, sectionId });
      if (r.children && r.children.length && expanded.has(r.id)) {
        visit(r.children, depth + 1, sectionId);
      }
    }
  }
  for (const s of sections) visit(s.rows, 0, s.id);
  return out;
}

function matchesQuery(row: LeftRailRow, q: string): boolean {
  if (!q) return true;
  const needle = q.toLowerCase();
  if (row.label.toLowerCase().includes(needle)) return true;
  if (row.id.toLowerCase().includes(needle)) return true;
  if (row.hint?.toLowerCase().includes(needle)) return true;
  if (row.children) return row.children.some((c) => matchesQuery(c, q));
  return false;
}

function filterRows(rows: LeftRailRow[], q: string): LeftRailRow[] {
  if (!q) return rows;
  const out: LeftRailRow[] = [];
  for (const r of rows) {
    if (matchesQuery(r, q)) {
      const filteredChildren = r.children ? filterRows(r.children, q) : undefined;
      out.push({ ...r, children: filteredChildren });
    }
  }
  return out;
}

export function LeftRail({
  sections,
  activeRowId,
  onRowActivate,
  onRowRename,
  defaultExpanded,
  onRowContextMenu,
}: LeftRailProps): JSX.Element {
  const [expanded, setExpanded] = useState<Set<string>>(() => new Set(defaultExpanded ?? []));
  const [query, setQuery] = useState('');
  const [focusedId, setFocusedId] = useState<string | undefined>(activeRowId);

  const filteredSections = useMemo(
    () =>
      query
        ? sections
            .map((s) => ({ ...s, rows: filterRows(s.rows, query) }))
            .filter((s) => s.rows.length > 0)
        : sections,
    [sections, query],
  );

  // Auto-expand all rows during search so matches are visible.
  const liveExpanded = useMemo(() => {
    if (!query) return expanded;
    const all = new Set<string>(expanded);
    function collect(rows: LeftRailRow[]): void {
      for (const r of rows) {
        if (r.children?.length) {
          all.add(r.id);
          collect(r.children);
        }
      }
    }
    for (const s of filteredSections) collect(s.rows);
    return all;
  }, [filteredSections, expanded, query]);

  const flat = useMemo(
    () => flatten(filteredSections, liveExpanded),
    [filteredSections, liveExpanded],
  );

  const moveFocus = useCallback(
    (delta: 1 | -1) => {
      if (!flat.length) return;
      const idx = focusedId ? flat.findIndex((r) => r.id === focusedId) : -1;
      const next = flat[(idx + delta + flat.length) % flat.length];
      setFocusedId(next.id);
    },
    [flat, focusedId],
  );

  const handleKey = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key === 'ArrowDown') {
        event.preventDefault();
        moveFocus(1);
      } else if (event.key === 'ArrowUp') {
        event.preventDefault();
        moveFocus(-1);
      } else if (event.key === 'ArrowRight') {
        if (!focusedId) return;
        event.preventDefault();
        setExpanded((prev) => {
          const next = new Set(prev);
          next.add(focusedId);
          return next;
        });
      } else if (event.key === 'ArrowLeft') {
        if (!focusedId) return;
        event.preventDefault();
        setExpanded((prev) => {
          if (!prev.has(focusedId)) return prev;
          const next = new Set(prev);
          next.delete(focusedId);
          return next;
        });
      } else if (event.key === 'Enter') {
        if (!focusedId) return;
        event.preventDefault();
        onRowActivate?.(focusedId);
      } else if (event.key === 'F2') {
        if (!focusedId) return;
        event.preventDefault();
        onRowRename?.(focusedId);
      }
    },
    [focusedId, moveFocus, onRowActivate, onRowRename],
  );

  return (
    <div className="flex h-full flex-col overflow-hidden bg-surface">
      <div className="sticky top-0 z-10 border-b border-border bg-surface px-3 py-2">
        <SearchField value={query} onChange={setQuery} />
      </div>
      <div
        role="tree"
        aria-label="Project browser"
        tabIndex={0}
        onKeyDown={handleKey}
        className="flex-1 overflow-y-auto py-2"
      >
        {filteredSections.map((s) => (
          <SectionBlock key={s.id} section={s}>
            {s.rows.map((r) => (
              <Row
                key={r.id}
                row={r}
                depth={0}
                expanded={liveExpanded}
                onToggle={(id) =>
                  setExpanded((prev) => {
                    const next = new Set(prev);
                    if (next.has(id)) next.delete(id);
                    else next.add(id);
                    return next;
                  })
                }
                onActivate={onRowActivate}
                onContextMenu={onRowContextMenu}
                activeRowId={activeRowId}
                focusedRowId={focusedId}
                setFocused={setFocusedId}
              />
            ))}
          </SectionBlock>
        ))}
        {filteredSections.length === 0 ? (
          <div className="px-5 py-3 text-xs text-muted">No matches.</div>
        ) : null}
      </div>
    </div>
  );
}

/** Slim (56 px) icon strip used by AppShell when the rail is collapsed. */
export function LeftRailCollapsed({ sections }: { sections: LeftRailSection[] }): JSX.Element {
  return (
    <nav
      aria-label="Project browser sections"
      className="flex h-full flex-col items-center gap-2 border-r border-border bg-surface py-3"
    >
      {sections.map((s) => {
        const Icon = s.icon ?? Icons.disclosureClosed;
        return (
          <button
            key={s.id}
            type="button"
            aria-label={s.label}
            title={s.label}
            className="inline-flex h-9 w-9 items-center justify-center rounded-md text-foreground hover:bg-surface-strong"
          >
            <Icon size={ICON_SIZE.toolPalette} aria-hidden="true" />
          </button>
        );
      })}
    </nav>
  );
}

function SearchField({
  value,
  onChange,
}: {
  value: string;
  onChange: (v: string) => void;
}): JSX.Element {
  return (
    <label className="flex items-center gap-2 rounded-md border border-border bg-background px-2 py-1.5 text-sm focus-within:ring-2 focus-within:ring-offset-0">
      <Icons.search size={ICON_SIZE.chrome} className="text-muted" aria-hidden="true" />
      <input
        type="search"
        placeholder="Search project"
        aria-label={IconLabels.search}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="flex-1 bg-transparent text-sm text-foreground outline-none placeholder:text-muted"
      />
    </label>
  );
}

function SectionBlock({
  section,
  children,
}: {
  section: LeftRailSection;
  children: ReactNode;
}): JSX.Element {
  return (
    <div className="mb-2">
      <div
        className="flex items-center gap-1.5 px-5 py-1 text-xs uppercase text-muted"
        style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
      >
        {section.icon ? <section.icon size={12} aria-hidden="true" /> : null}
        <span>{section.label}</span>
      </div>
      {children}
    </div>
  );
}

interface RowProps {
  row: LeftRailRow;
  depth: number;
  expanded: ReadonlySet<string>;
  onToggle: (id: string) => void;
  onActivate?: (id: string) => void;
  onContextMenu?: (id: string, event: { x: number; y: number }) => void;
  activeRowId?: string;
  focusedRowId?: string;
  setFocused: (id: string) => void;
}

function Row({
  row,
  depth,
  expanded,
  onToggle,
  onActivate,
  onContextMenu,
  activeRowId,
  focusedRowId,
  setFocused,
}: RowProps): JSX.Element {
  const hasChildren = !!row.children?.length;
  const isOpen = expanded.has(row.id);
  const isActive = row.id === activeRowId;
  const isFocused = row.id === focusedRowId;
  const ref = useRef<HTMLButtonElement | null>(null);

  useEffect(() => {
    if (isFocused) ref.current?.focus({ preventScroll: true });
  }, [isFocused]);

  const indentStyle: CSSProperties = {
    paddingLeft: `calc(var(--space-5) + ${depth} * var(--space-5))`,
  };

  return (
    <div role="none">
      <button
        ref={ref}
        type="button"
        role="treeitem"
        aria-level={depth + 1}
        aria-expanded={hasChildren ? isOpen : undefined}
        aria-selected={isActive}
        tabIndex={isFocused ? 0 : -1}
        onClick={() => {
          setFocused(row.id);
          if (hasChildren) onToggle(row.id);
          onActivate?.(row.id);
        }}
        onContextMenu={(event) => {
          if (!onContextMenu) return;
          event.preventDefault();
          onContextMenu(row.id, { x: event.clientX, y: event.clientY });
        }}
        data-testid={`left-rail-row-${row.id}`}
        data-active={isActive ? 'true' : 'false'}
        style={indentStyle}
        className={[
          'flex h-7 w-full items-center gap-1.5 pr-3 text-sm',
          isActive ? 'bg-accent-soft text-foreground' : 'text-foreground hover:bg-surface-strong',
        ].join(' ')}
      >
        <span className="inline-flex w-4 items-center justify-center">
          {hasChildren ? (
            isOpen ? (
              <Icons.disclosureOpen size={12} aria-hidden="true" />
            ) : (
              <Icons.disclosureClosed size={12} aria-hidden="true" />
            )
          ) : null}
        </span>
        {row.icon ? <row.icon size={12} aria-hidden="true" className="text-muted" /> : null}
        <span className="truncate">{row.label}</span>
        {row.hint ? <span className="ml-auto truncate text-xs text-muted">{row.hint}</span> : null}
      </button>
      {hasChildren && isOpen
        ? (row.children ?? []).map((c) => (
            <Row
              key={c.id}
              row={c}
              depth={depth + 1}
              expanded={expanded}
              onToggle={onToggle}
              onActivate={onActivate}
              onContextMenu={onContextMenu}
              activeRowId={activeRowId}
              focusedRowId={focusedRowId}
              setFocused={setFocused}
            />
          ))
        : null}
    </div>
  );
}

