function makeRailingMesh(
  railing: Extract<Element, { kind: 'railing' }>,
  _elementsById: Record<string, Element>,
  paint: ViewportPaintBundle | null,
): THREE.LineSegments {
  const pts = (railing.pathMm ?? []).map(
    ([x, z]: [number, number]) => new THREE.Vector3(x / 1000, (railing.baseLevelElevMm ?? 0) / 1000, z / 1000),
  );
  const geom = new THREE.BufferGeometry().setFromPoints(pts.length >= 2 ? pts : [new THREE.Vector3(), new THREE.Vector3()]);
  const mat = new THREE.LineBasicMaterial({ color: paint?.categories.railing?.color ?? '#a3a3a3' });
  const mesh = new THREE.LineSegments(geom, mat);
  mesh.userData.bimPickId = railing.id;
  return mesh;
}

function makeSiteMesh(
  site: Extract<Element, { kind: 'site' }>,
  _elementsById: Record<string, Element>,
  paint: ViewportPaintBundle | null,
): THREE.Mesh {
  const b = xzBoundsMm(site.boundaryMm ?? []);
  const w = Math.max((b.maxX - b.minX) / 1000, 0.1);
  const d = Math.max((b.maxZ - b.minZ) / 1000, 0.1);
  const geom = new THREE.BoxGeometry(w, 0.05, d);
  const mat = new THREE.MeshStandardMaterial({ color: paint?.categories.site?.color ?? '#6b7280' });
  const mesh = new THREE.Mesh(geom, mat);
  mesh.position.set((b.minX + b.maxX) / 2000, -0.025, (b.minZ + b.maxZ) / 2000);
  mesh.userData.bimPickId = site.id;
  return mesh;
}

type ViewerCatKey = 'wall' | 'floor' | 'roof' | 'stair' | 'door' | 'window' | 'room' | 'railing' | 'site';

